        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[VolSurfaceResponse](sbeTemplateId=");
            builder.Append(VolSurfaceResponse.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(VolSurfaceResponse.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != VolSurfaceResponse.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(VolSurfaceResponse.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != VolSurfaceResponse.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(VolSurfaceResponse.BlockLength);
            builder.Append("):");

            builder.Append("RequestID=");
            builder.Append(this.RequestID);
            builder.Append('|');
            builder.Append("Success=");
            builder.Append(this.Success);
            builder.Append('|');
            builder.Append("MarketDataSnapshotTime=");
            builder.Append(this.MarketDataSnapshotTime);
            builder.Append('|');
            builder.Append("VolaCurvePoints=[");
            var volaCurvePoints = this.VolaCurvePoints;
            if (volaCurvePoints.Count > 0)
            {
                var first = true;
                while (volaCurvePoints.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    volaCurvePoints.Next().BuildString(builder);
                }
            }
            builder.Append("]");
            builder.Append('|');
            builder.Append("PutsMarketData=[");
            var putsMarketData = this.PutsMarketData;
            if (putsMarketData.Count > 0)
            {
                var first = true;
                while (putsMarketData.HasNext)
